def count_distinct_pairs(nums, target):
    """
    Returns the number of distinct unordered value pairs in the list that sum to the target.

    Args:
        nums (list): A list of integers.
        target (int): The target sum.

    Returns:
        int: The number of distinct unordered value pairs that sum to the target.

    Edge case: An empty list returns 0.
    """
    if not nums:
        return 0

    num_count = {}
    for num in nums:
        if num in num_count:
            num_count[num] += 1
        else:
            num_count[num] = 1

    pairs = set()
    for num in num_count:
        complement = target - num
        if complement != num and complement in num_count:
            pair = tuple(sorted((num, complement)))
            pairs.add(pair)

    return len(pairs)
